 local Round = function(num) return math.floor(num + 0.5) end local function ChangeCastSpell(self) local tags = { "doing" , "busy" , "canrotate" , "spell" } for k, v in pairs(tags) do self.tags[v] = true end self.onenter = function(inst) inst.components.playercontroller:Enable(false) inst.AnimState:PlayAnimation( "staff" ) inst.components.locomotor:Stop() local staff = inst.components.inventory:GetEquippedItem(EQUIPSLOTS.HANDS) local spellcaster = staff and staff.components.spellcaster local pos = inst:GetPosition() local rot = inst.Transform:GetRotation() local SpawnCastFX = spellcaster and spellcaster.SpawnCastFX if SpawnCastFX then inst.stafffx = SpawnCastFX(spellcaster, pos, rot) else inst.stafffx = SpawnPrefab( "staffcastfx" ) inst.stafffx.Transform:SetPosition(pos.x, pos.y, pos.z) inst.stafffx.Transform:SetRotation(rot) end local color = staff and staff.fxcolour or staff and staff.fxcolor if color and inst.stafffx.AnimState then inst.stafffx.AnimState:SetMultColour(color[0x1] or color.x or color.r, color[0x2] or color.y or color.g, color[0x3] or color.z or color.b, 0x1) elseif color then inst.stafffx.tint = color end end self.onexit = function(inst) inst.components.playercontroller:Enable(true) if inst.stafffx then inst.stafffx:Remove() end local staff = inst.components.inventory:GetEquippedItem(EQUIPSLOTS.HANDS) if staff then local spellcaster = staff.components.spellcaster if spellcaster then local act = inst.bufferedaction if spellcaster.OnChannelEnd and inst.dycIsCharChanneling then spellcaster.OnChannelEnd(spellcaster, inst, act and act.target or nil, act and act.pos or nil) end end end inst.dycIsCharChanneling = false end self.timeline = {TimeEvent(0xd * FRAMES, function(inst) inst.SoundEmitter:PlaySound( "dontstarve/wilson/use_gemstaff" ) local staff = inst.components.inventory:GetEquippedItem(EQUIPSLOTS.HANDS) if staff and staff.castfast then local spellcaster = staff.components.spellcaster if spellcaster then spellcaster.caster = inst local act = inst.bufferedaction if spellcaster.OnChannelStart then spellcaster.OnChannelStart(spellcaster, inst, act and act.target or nil, act and act.pos or nil) end end inst:PerformBufferedAction() if spellcaster then spellcaster.caster = nil end inst.dycIsCharChanneling = true end end), TimeEvent(0x0 * FRAMES, function(inst) inst.stafflight = SpawnPrefab( "staff_castinglight" ) local staff = inst.components.inventory:GetEquippedItem(EQUIPSLOTS.HANDS) local pos = inst:GetPosition() local colour = staff and staff.fxcolour or {0x1, 0x1, 0x1} inst.stafflight.Transform:SetPosition(pos.x, pos.y, pos.z) inst.stafflight.setupfn(inst.stafflight, colour, 1.9,.33) end), TimeEvent(0x35 * FRAMES, function(inst) local staff = inst.components.inventory:GetEquippedItem(EQUIPSLOTS.HANDS) if not staff or not staff.castfast then local spellcaster = staff and staff.components.spellcaster if spellcaster then spellcaster.caster = inst local act = inst.bufferedaction if spellcaster.OnChannelStart then spellcaster.OnChannelStart(spellcaster, inst, act and act.target or nil, act and act.pos or nil) end end inst:PerformBufferedAction() if spellcaster then spellcaster.caster = nil end inst.dycIsCharChanneling = true end end), TimeEvent(0x3c * FRAMES, function(inst) local staff = inst.components.inventory:GetEquippedItem(EQUIPSLOTS.HANDS) if staff and staff.endcast then staff.endcast(staff) end if staff then local spellcaster = staff.components.spellcaster if spellcaster then local act = inst.bufferedaction if spellcaster.OnChannelEnd and inst.dycIsCharChanneling then spellcaster.OnChannelEnd(spellcaster, inst, act and act.target or nil, act and act.pos or nil) end end end inst.dycIsCharChanneling = false end),} end local function ChangeAttack(self) for k, v in pairs(self.timeline) do v.dycFrameIndex = Round(v.time / FRAMES) end local oldOnEnter = self.onenter self.onenter = function(inst) if oldOnEnter then oldOnEnter(inst) end local charBonusPercentage = 0x0 if inst.GetCharacterBonus then charBonusPercentage = inst:GetCharacterBonus( "attackspeed_percent" ) end local attackSpeedMultiplier = math.max(0x1 + charBonusPercentage, 0.1) inst.AnimState:SetDeltaTimeMultiplier(attackSpeedMultiplier) for k, v in pairs(self.timeline) do v.time = Round(v.dycFrameIndex / attackSpeedMultiplier) * FRAMES end local combat = inst.components.combat if combat then if not inst.dycOldMinAttackPeriod then inst.dycOldMinAttackPeriod = combat.min_attack_period or 0.5 end combat.min_attack_period = inst.dycOldMinAttackPeriod / attackSpeedMultiplier end end local oldOnExit = self.onexit self.onexit = function(inst) if oldOnExit then oldOnExit(inst) end inst.sg:RemoveStateTag( "attack" ) inst.AnimState:SetDeltaTimeMultiplier(0x1) end end local function ChangeToolBrokeEvent(self) self.fn = function(inst, data) local inventory = inst.components.inventory local toolObj = inventory and inventory:GetEquippedItem(EQUIPSLOTS.HANDS) local tool = toolObj and toolObj.components.tool if inst.sg:HasStateTag( "playing" ) then inst.toolwantstobreak = true else if not tool or not tool.dycNoBrokeAnim then inst.sg:GoToState( "toolbroke" , data.tool) end end end end local function DYCSGWilson(self) local states = self.states local castspell = states.castspell if castspell then ChangeCastSpell(castspell) end local attack = states.attack if attack then ChangeAttack(attack) end local events = self.events local toolBrokeEvent = events.toolbroke if toolBrokeEvent then ChangeToolBrokeEvent(toolBrokeEvent) end end return DYCSGWilson 